def find_length(string):
    max_length = 0
    left, right = 0, 0
    for j in range(len(string)):
        if string[j] == '1':
            right += 1
        while right - left > max_length:
            if string[left] == '1':
                right -= 1
            left += 1
        max_length = max(max_length, right - left)
    return max_length

