def sum_of_divisors(num):
    divisors = [0] * (num + 1)
    for i in range(2, int(num**(1.0 / 2)) + 1):
        if num % i == 0:
            divisors[i] = i
            if i != num / i:
                divisors[int(num / i)] = int(num / i)

    return sum(divisors) + num

